t the elevation mask angle of the receiver } ​ @Override public void getEbubbleInfo(EbubbleInfo ebubbleInfo) throws RemoteException { // Set the inclination sensor data to output at a fixed frequency } ​ @Override public void getMagnetometerInfo(MagnetometerInfo magnetometerInfo) throws RemoteException { // Set the gyroscope data to output at @Override public void getBasePositionList(BasePositionInfoArray basePositionInfoArray) throws RemoteException { // Get the advanced base station information list of the receiver } ​ @Override public void getBasePositionDifference(float v) throws RemoteException { // Get the translation amount of the advanced base station of the receiver } ​ @Override public void getTransmissionInfo(byte[] bytes) throws RemoteException { // RTCM3 message } ​ /*** Handles CHC_MESSAGE_TYPE_SYSTEM *******************************************************/ ​ @Override public void getReceiverInfo(ReceiverInfo info) throws RemoteException { // Receiver information } ​ @Override public void getRegCode(String regCode) throws RemoteException { // Get the receiver registration code } ​ @Override public void getFileRecordStatus(FileRecordStatus status) throws RemoteException { // File recording status } ​ @Override public void getFileRecordParams(FileRecordInfo info) throws RemoteException { // File recording parameters } ​ @Override public void getFileRecordAutoStart(boolean isAuto) throws RemoteException { // Whether the file is automatically recorded } ​ @Override public void getComBaudrate(Baudrate baudrate) throws RemoteException { // Get the baud rate of the receiver serial port } ​ @Override public void getExpireDate(ExpireDate expireDate) throws RemoteException { // Get the receiver registration expiration date } ​ @Override public void getBattteyLife(int i) throws RemoteException { // Get the receiver battery life: 12 indicates external power, &lt;= 2 indicates low battery, &lt;= 5 indicates 1 bar, &lt;= 9 indicates 2 bars } ​ /*** Handles CHC_MESSAGE_TYPE_PDA *******************************************************/ ​ @Override public void getModemCommunicationMode(ModemCommunicationMode mode) throws RemoteException { // Get the 3G module mode } ​ @Override public void getModemDialStatus(ModemDialStatus status) throws RemoteException { // Get the 3G module dial status } ​ @Override public void getCsdDialStatus(ModemDialStatus status) throws RemoteException { // Get the 3G module dial status (GSM) } ​ @Override public void getCsdInfo(CsdInfo info) throws RemoteException { // Get the 3G module GSM dial parameters } ​ @Override public void getModemAutoDialParams(ModemDialParams params) throws RemoteException { // Get the 3G module dial parameters } ​ @Override public void getModemAutoDial(boolean b) throws RemoteException { // Get whether the 3G module auto dials } ​ @Override public void getModemAutoPowerOn(boolean b) throws RemoteException { // Get whether the 3G module auto powers on } ​ @Override public void getModemPowerStatus(PowerStatus powerStatus) throws RemoteException { // Get the power status of the 3G module } ​ @Override public void getWifiAutoPowerOn(boolean auto) throws RemoteException { // Get whether the receiver&#39;s WIFI module auto powers on } ​ @Override public void getWifiInfo(ReceiverWifiInfo info) throws RemoteException { // Get the parameters of the receiver&#39;s WIFI module } ​ @Override public void getWifiStatus(PowerStatus status) throws RemoteException { // Get the WIFI status } ​ @Override public void getModemSignal(ModemSignal modemSignal) throws RemoteException { // Get the signal strength of the 3G module } ​ @Override public void getModemBandMode(ModemBandMode modemBandMode) throws RemoteException { // Get the frequency band of the 3G module } ​ /*** Handles CHC_MESSAGE_TYPE_DATALINK ******************************************************/ ​ @Override public void getRadioPowerStatus(PowerStatus status) throws RemoteException { // Get the power status of the receiver&#39;s radio